import type { CareerQuestion } from "./rrt-questions";

export const himQuestionsBatch11: CareerQuestion[] = [
  { id: "him-953", stem: "Which MS-DRG modifier affects reimbursement for a major complication or comorbidity?", options: ["MCC — Major Complication/Comorbidity shifts the case to a higher-paying DRG","CC — Complication/Comorbidity only","No modifier is needed","PDX modifier"], correctIndex: 0, rationale: "MCCs are conditions that significantly increase resource utilization and shift the DRG to a higher-weighted tier, resulting in greater reimbursement.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Systems" },
  { id: "him-954", stem: "A coder assigns Z87.891 for a personal history of nicotine dependence. When is this code appropriate?", options: ["When the patient formerly used tobacco but has since quit","When the patient currently uses tobacco","When the patient has never used tobacco","Only during prenatal visits"], correctIndex: 0, rationale: "Z87.891 is used for former tobacco/nicotine dependence. Current use is coded with F17.- series or Z72.0.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Z Codes" },
  { id: "him-955", stem: "Under HIPAA, a covered entity must respond to an individual's request for access to their PHI within:", options: ["30 days, with one 30-day extension if needed","7 business days","90 days","No time limit is specified"], correctIndex: 0, rationale: "HIPAA requires response within 30 days of the request. A single 30-day extension is permitted if written notice with the reason is provided to the individual.", difficulty: 2, category: "Privacy & Confidentiality", topic: "HIPAA Access Rights" },
  { id: "him-956", stem: "The purpose of a Clinical Documentation Improvement (CDI) query is to:", options: ["Clarify ambiguous or incomplete documentation to ensure accurate code assignment","Change the physician's diagnosis","Increase reimbursement through upcoding","Correct billing errors after claim submission"], correctIndex: 0, rationale: "CDI queries ask providers to clarify, add specificity, or resolve conflicting documentation. They must be non-leading and compliant with AHIMA guidelines.", difficulty: 2, category: "Clinical Documentation", topic: "CDI Queries" },
  { id: "him-957", stem: "Which ICD-10-PCS root operation describes cutting into a body part without draining fluids or gases?", options: ["Division (8)","Drainage (9)","Release (N)","Excision (B)"], correctIndex: 0, rationale: "Division (8) is cutting into a body part without draining. Drainage (9) takes out fluids/gases. Release (N) frees a body part from constraint.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-PCS Root Operations" },
  { id: "him-958", stem: "Data governance in healthcare includes:", options: ["Policies, procedures, and standards for managing data quality, security, and availability across the organization","Only IT department responsibilities","Hardware maintenance schedules","Vendor contract negotiations"], correctIndex: 0, rationale: "Data governance encompasses organizational policies for data quality, integrity, security, availability, and usability. It involves stakeholders across departments, not just IT.", difficulty: 2, category: "Health Informatics", topic: "Data Governance" },
  { id: "him-959", stem: "A query from a CDI specialist should be:", options: ["Non-leading, clinically relevant, and provide options without suggesting a preferred answer","Directive, telling the physician which diagnosis to document","Submitted only after discharge","Verbal only, never written"], correctIndex: 0, rationale: "Compliant queries are non-leading, present clinical indicators, and allow physicians to make independent documentation decisions without suggesting specific responses.", difficulty: 2, category: "Clinical Documentation", topic: "CDI Query Standards" },
  { id: "him-960", stem: "The Recovery Audit Contractor (RAC) program is designed to:", options: ["Identify and recover improper Medicare payments through claim review","Provide additional Medicare funding to hospitals","Replace the OIG audit function","Audit only outpatient claims"], correctIndex: 0, rationale: "RACs identify overpayments and underpayments to Medicare providers through automated and complex claim reviews. Providers can appeal RAC determinations.", difficulty: 2, category: "Revenue Cycle Management", topic: "Medicare Audits" },
  { id: "him-961", stem: "In ICD-10-CM, a manifestation code:", options: ["Cannot be sequenced as the principal diagnosis and must be preceded by the underlying condition","Can be used as a standalone code","Is always a primary diagnosis","Has no sequencing rules"], correctIndex: 0, rationale: "Manifestation codes (in italics/brackets) represent conditions due to underlying diseases. They must be sequenced after the etiology code and cannot be the principal diagnosis.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Conventions" },
  { id: "him-962", stem: "The charge description master (CDM) is maintained to:", options: ["Ensure accurate charge capture by linking services to appropriate CPT/HCPCS codes and revenue codes","Track patient demographics","Manage employee schedules","Store clinical documentation"], correctIndex: 0, rationale: "The CDM (chargemaster) contains the universe of services a facility provides, mapped to procedure codes, revenue codes, and prices. Accuracy is critical for proper billing.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-963", stem: "Which body system character in ICD-10-PCS represents procedures on the heart and great vessels?", options: ["2","0","5","D"], correctIndex: 0, rationale: "In ICD-10-PCS Medical and Surgical section (0), body system character 2 represents the Heart and Great Vessels.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-PCS Structure" },
  { id: "him-964", stem: "The AHIMA Code of Ethics requires HIM professionals to:", options: ["Protect the integrity of health information, maintain confidentiality, and advocate for ethical practices","Maximize revenue at all costs","Only follow employer directives regardless of legality","Share PHI freely for research"], correctIndex: 0, rationale: "AHIMA's Code of Ethics mandates protecting data integrity, confidentiality, patient rights, and advocating for ethical health information management practices.", difficulty: 1, category: "Legal & Compliance", topic: "Professional Ethics" },
  { id: "him-965", stem: "A patient is admitted for chemotherapy and has metastatic colon cancer. The principal diagnosis is:", options: ["Z51.11 Encounter for antineoplastic chemotherapy","C18.9 Malignant neoplasm of colon","C79.9 Secondary malignant neoplasm, unspecified","Z85.038 Personal history of colon cancer"], correctIndex: 0, rationale: "When admission is solely for chemotherapy, the encounter code Z51.11 is sequenced first. The malignancy codes are listed as additional diagnoses.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Neoplasm Coding" },
  { id: "him-966", stem: "Concurrent coding refers to:", options: ["Reviewing and coding records while the patient is still in the hospital","Coding only after discharge","Coding by multiple coders simultaneously","Retrospective coding audits"], correctIndex: 0, rationale: "Concurrent coding occurs during the patient's stay, allowing real-time CDI queries and timely identification of documentation gaps before discharge.", difficulty: 2, category: "Clinical Documentation", topic: "Coding Processes" },
  { id: "him-967", stem: "Under the HITECH Act, meaningful use requirements include:", options: ["Demonstrating the use of certified EHR technology to improve quality, safety, and efficiency","Only purchasing EHR software","Maintaining paper records alongside electronic records","Using any commercial software system"], correctIndex: 0, rationale: "HITECH's meaningful use (now Promoting Interoperability) requires providers to demonstrate meaningful use of certified EHR technology through specific measures.", difficulty: 2, category: "Health Informatics", topic: "EHR Regulations" },
  { id: "him-968", stem: "The All Patient Refined DRG (APR-DRG) system differs from MS-DRGs by:", options: ["Including severity of illness and risk of mortality subclasses for each base DRG","Using only principal diagnosis","Excluding procedure codes","Being used only for outpatient services"], correctIndex: 0, rationale: "APR-DRGs assign each case a severity of illness (1-4) and risk of mortality (1-4) subclass, providing more granular classification than MS-DRGs.", difficulty: 3, category: "Revenue Cycle Management", topic: "DRG Systems" },
  { id: "him-969", stem: "A Notice of Privacy Practices (NPP) must include:", options: ["A description of how the covered entity may use and disclose PHI, individual rights, and entity obligations","Only the facility's contact information","A list of all patients seen","Insurance billing rates"], correctIndex: 0, rationale: "The NPP must describe PHI uses and disclosures, patient rights (access, amendment, accounting of disclosures), and the entity's legal duties regarding PHI.", difficulty: 2, category: "Privacy & Confidentiality", topic: "HIPAA NPP" },
  { id: "him-970", stem: "Computer-assisted coding (CAC) technology:", options: ["Uses NLP to suggest codes from clinical documentation, which must be validated by a human coder","Replaces the need for human coders entirely","Only works with ICD-9-CM","Cannot process unstructured text"], correctIndex: 0, rationale: "CAC uses natural language processing to auto-suggest codes from documentation. Human coders must review, validate, and finalize code assignments.", difficulty: 2, category: "Health Informatics", topic: "Coding Technology" },
  { id: "him-971", stem: "The ICD-10-CM Alphabetic Index is used to:", options: ["Locate the appropriate code or code range, which must then be verified in the Tabular List","Assign final codes without cross-referencing","Replace the Tabular List","Code procedures only"], correctIndex: 0, rationale: "The Alphabetic Index is the starting point for code lookup. Coders must always verify the suggested code in the Tabular List for specificity, instructional notes, and accuracy.", difficulty: 1, category: "Clinical Classification", topic: "ICD-10-CM Structure" },
  { id: "him-972", stem: "A data dictionary in healthcare information systems:", options: ["Defines data elements, their attributes, formats, and allowable values to ensure consistency","Is a medical terminology textbook","Contains only patient names","Is used only by programmers"], correctIndex: 0, rationale: "A data dictionary standardizes data element definitions, formats, sources, and valid values across the organization, supporting data quality and interoperability.", difficulty: 2, category: "Health Informatics", topic: "Data Management" },
  { id: "him-973", stem: "SNOMED CT is primarily used for:", options: ["Clinical terminology standardization enabling interoperable electronic health records","Billing and reimbursement","Scheduling appointments","Patient registration"], correctIndex: 0, rationale: "SNOMED CT is a comprehensive clinical terminology system enabling consistent representation of clinical concepts across EHR systems for interoperability.", difficulty: 2, category: "Health Informatics", topic: "Clinical Terminologies" },
  { id: "him-974", stem: "The Uniform Hospital Discharge Data Set (UHDDS) defines principal diagnosis as:", options: ["The condition established after study to be chiefly responsible for occasioning the admission","The most severe condition","The first condition listed","The condition with the highest reimbursement"], correctIndex: 0, rationale: "UHDDS defines principal diagnosis as the condition determined after study to be chiefly responsible for the admission. This may differ from the admitting diagnosis.", difficulty: 2, category: "Data Content & Structure", topic: "Data Sets" },
  { id: "him-975", stem: "In CPT, a separate procedure designation means:", options: ["The procedure is commonly part of a more comprehensive procedure and should only be reported separately when performed independently","The procedure always requires a separate claim","The procedure cannot be billed","The procedure is experimental"], correctIndex: 0, rationale: "Separate procedure codes are typically included in more comprehensive procedures. They are reported only when performed independently or at a different site.", difficulty: 3, category: "Clinical Classification", topic: "CPT Coding" },
  { id: "him-976", stem: "Risk adjustment in value-based payment models uses diagnosis codes to:", options: ["Predict expected healthcare costs and adjust payments based on patient severity and complexity","Reduce the number of codes assigned","Simplify billing processes","Eliminate the need for documentation"], correctIndex: 0, rationale: "Risk adjustment (e.g., CMS-HCC model) uses diagnosis codes to predict costs. Accurate coding ensures appropriate payment for managing sicker patient populations.", difficulty: 3, category: "Revenue Cycle Management", topic: "Risk Adjustment" },
  { id: "him-977", stem: "The Joint Commission requires medical records to be completed within:", options: ["30 days following discharge","7 days","90 days","No time requirement exists"], correctIndex: 0, rationale: "The Joint Commission standard requires medical records to be completed within 30 days post-discharge. Delinquent records may result in loss of privileges.", difficulty: 2, category: "Data Content & Structure", topic: "Record Completion" },
  { id: "him-978", stem: "A crosswalk in medical coding refers to:", options: ["A mapping between two coding systems (e.g., ICD-10 to ICD-9, CPT to ICD-10) to facilitate translation","A physical pathway in a hospital","A patient transfer protocol","An audit trail"], correctIndex: 0, rationale: "Crosswalks map codes between classification systems (e.g., GEMs between ICD-9 and ICD-10). They facilitate translation but may not always provide exact one-to-one matches.", difficulty: 2, category: "Clinical Classification", topic: "Code Mapping" },
  { id: "him-979", stem: "Clinical decision support systems (CDSS) in EHRs:", options: ["Provide evidence-based alerts, reminders, and recommendations to clinicians at the point of care","Replace physician judgment entirely","Only track billing information","Are limited to pharmacy systems"], correctIndex: 0, rationale: "CDSS tools integrate clinical knowledge with patient data to provide decision support: drug interaction alerts, diagnostic suggestions, preventive care reminders.", difficulty: 2, category: "Health Informatics", topic: "Clinical Decision Support" },
  { id: "him-980", stem: "A present on admission (POA) indicator of 'N' means:", options: ["The condition was not present at the time of inpatient admission","The condition was present on admission","It is clinically undetermined","The condition is exempt from POA reporting"], correctIndex: 0, rationale: "POA indicator N = not present on admission. Y = present. U = insufficient documentation to determine. W = not applicable. 1 = exempt.", difficulty: 2, category: "Clinical Classification", topic: "POA Indicators" },
  { id: "him-981", stem: "The OIG Work Plan identifies:", options: ["Areas of focus for federal fraud and abuse investigations in healthcare","New CPT codes for the upcoming year","HIPAA privacy rule updates","Joint Commission survey schedules"], correctIndex: 0, rationale: "The OIG Work Plan outlines planned audits, investigations, and evaluations targeting fraud, waste, and abuse in federal healthcare programs.", difficulty: 2, category: "Legal & Compliance", topic: "Fraud & Abuse" },
  { id: "him-982", stem: "HL7 FHIR (Fast Healthcare Interoperability Resources) is designed to:", options: ["Enable healthcare data exchange using modern web-based API standards (RESTful)","Replace all existing EHR systems","Only work with legacy systems","Manage hospital billing exclusively"], correctIndex: 0, rationale: "FHIR uses RESTful APIs, JSON/XML, and modular resources to enable efficient healthcare data exchange. It is designed for modern web and mobile applications.", difficulty: 3, category: "Health Informatics", topic: "Interoperability Standards" },
  { id: "him-983", stem: "A compliance program for coding must include:", options: ["Written policies, training, auditing, reporting mechanisms, and corrective action procedures","Only annual training","External audits exclusively","Physician education only"], correctIndex: 0, rationale: "OIG compliance program elements: written standards, compliance officer, training, internal monitoring/auditing, reporting mechanisms, enforcement, and corrective action.", difficulty: 2, category: "Legal & Compliance", topic: "Compliance Programs" },
  { id: "him-984", stem: "Case mix index (CMI) is calculated by:", options: ["Summing all DRG relative weights for a period and dividing by the total number of discharges","Counting the number of beds occupied","Averaging length of stay","Dividing revenue by expenses"], correctIndex: 0, rationale: "CMI = total DRG relative weights / total discharges. Higher CMI indicates a more complex case mix and correlates with higher resource utilization.", difficulty: 3, category: "Revenue Cycle Management", topic: "Case Mix Analysis" },
  { id: "him-985", stem: "The purpose of a release of information (ROI) log is to:", options: ["Track all disclosures of PHI as required by HIPAA's accounting of disclosures provision","Record employee attendance","Track prescription refills","Log system downtime"], correctIndex: 0, rationale: "HIPAA requires an accounting of PHI disclosures (with exceptions for TPO). The ROI log documents to whom, when, what, and why PHI was disclosed.", difficulty: 2, category: "Privacy & Confidentiality", topic: "Accounting of Disclosures" },
  { id: "him-986", stem: "The ICD-10-CM code for Type 2 diabetes with diabetic chronic kidney disease Stage 3 requires:", options: ["E11.22 for the diabetes with CKD and N18.3 for the CKD stage","Only E11.9","Only N18.3","E10.22 and N18.3"], correctIndex: 0, rationale: "Type 2 DM with CKD requires E11.22 (Type 2 DM with diabetic CKD) plus N18.3 to specify Stage 3. Both codes are needed per ICD-10-CM guidelines.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Diabetes Coding" },
  { id: "him-987", stem: "Data analytics in HIM can be used for:", options: ["Identifying coding patterns, monitoring quality metrics, detecting fraud, and supporting population health management","Only generating financial reports","Replacing clinical judgment","Scheduling staff"], correctIndex: 0, rationale: "HIM analytics encompasses coding quality monitoring, revenue cycle analysis, clinical quality measures, compliance auditing, and population health analytics.", difficulty: 2, category: "Health Informatics", topic: "Healthcare Analytics" },
  { id: "him-988", stem: "An encoder in medical coding is:", options: ["Software that assists coders in finding and validating appropriate codes through logic-based pathways","A physical device that scans documents","A type of medical record","A billing clearinghouse"], correctIndex: 0, rationale: "Encoders are software tools that guide coders through code selection using logic trees, search functions, and edit checks. They support but do not replace coder judgment.", difficulty: 1, category: "Health Informatics", topic: "Coding Technology" },
  { id: "him-989", stem: "The Conditions of Participation (CoPs) for Medicare require hospitals to:", options: ["Maintain medical records that are accurately documented, promptly completed, and readily accessible","Only submit claims electronically","Have a minimum bed count","Use only paper records"], correctIndex: 0, rationale: "Medicare CoPs establish minimum standards for hospitals including medical record requirements: accuracy, completeness, timeliness, authentication, and accessibility.", difficulty: 2, category: "Legal & Compliance", topic: "Medicare Requirements" },
  { id: "him-990", stem: "A clinical pathway (care map) is:", options: ["A standardized, evidence-based multidisciplinary plan outlining expected course of treatment for a specific diagnosis","A physical map of the hospital","A coding guideline","A staffing schedule"], correctIndex: 0, rationale: "Clinical pathways standardize care for specific diagnoses/procedures, outlining expected interventions, milestones, and outcomes to reduce variation and improve quality.", difficulty: 2, category: "Data Content & Structure", topic: "Clinical Documentation" },
  { id: "him-991", stem: "The National Drug Code (NDC) is used to identify:", options: ["Drugs and biologicals in the United States by labeler, product, and package","Medical devices only","Laboratory tests","Radiology procedures"], correctIndex: 0, rationale: "NDC is a universal identifier for drugs: labeler code (manufacturer), product code (drug/strength/form), and package code (size/type). Required for drug billing.", difficulty: 2, category: "Clinical Classification", topic: "Code Systems" },
  { id: "him-992", stem: "In ICD-10-PCS, the approach character 'Percutaneous' means:", options: ["Entry by puncture or minor incision through the skin, mucous membrane, or other body layer to reach the operative site","Entry through a natural opening","Open surgical approach","External approach without incision"], correctIndex: 0, rationale: "Percutaneous (3) involves puncture/minor incision through skin or mucous membrane. Differs from Open (0), Percutaneous Endoscopic (4), and via Natural Opening (7/8).", difficulty: 2, category: "Clinical Classification", topic: "ICD-10-PCS Approaches" },
  { id: "him-993", stem: "Benchmarking in HIM involves:", options: ["Comparing organizational performance metrics against industry standards or best practices","Setting maximum salary levels","Counting office supplies","Recording patient complaints"], correctIndex: 0, rationale: "Benchmarking compares KPIs (coding accuracy, DNFB days, coder productivity) against internal targets and external industry standards to identify improvement opportunities.", difficulty: 2, category: "Health Informatics", topic: "Performance Improvement" },
  { id: "him-994", stem: "The Anti-Kickback Statute prohibits:", options: ["Offering, paying, soliciting, or receiving anything of value to induce or reward referrals for services covered by federal programs","All physician referrals","Marketing of healthcare services","Accepting insurance payments"], correctIndex: 0, rationale: "The AKS prohibits remuneration intended to induce referrals for federal healthcare program services. Violations can result in criminal penalties, fines, and exclusion.", difficulty: 2, category: "Legal & Compliance", topic: "Fraud & Abuse Laws" },
  { id: "him-995", stem: "A discharged not final billed (DNFB) report tracks:", options: ["Inpatient accounts discharged but not yet billed due to incomplete coding or missing documentation","Denied claims","Paid claims","Outpatient registrations"], correctIndex: 0, rationale: "DNFB represents revenue tied up in unbilled accounts. Monitoring DNFB days is critical for cash flow management. Target is typically <5 days.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Cycle Metrics" },
  { id: "him-996", stem: "The purpose of a physician champion in CDI is to:", options: ["Serve as a clinical peer advocate who educates providers and supports documentation improvement initiatives","Code medical records","Audit billing claims","Manage IT systems"], correctIndex: 0, rationale: "Physician champions bridge the gap between CDI specialists and the medical staff, promoting documentation improvement through peer education and advocacy.", difficulty: 2, category: "Clinical Documentation", topic: "CDI Program Structure" },
  { id: "him-997", stem: "ICD-10-CM guidelines for coding HIV disease require:", options: ["Confirmation by the provider to assign B20 (HIV disease); inconclusive test results use R75","Any positive lab test without provider confirmation","Patient self-report only","Coding only when the patient has AIDS"], correctIndex: 0, rationale: "B20 requires provider confirmation of HIV disease. R75 is used for inconclusive HIV test findings. Z21 is used for asymptomatic HIV infection status.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Infectious Disease" },
  { id: "him-998", stem: "Enterprise master patient index (EMPI) management is critical for:", options: ["Ensuring each patient has a single, accurate identifier across all systems in a healthcare organization","Tracking employee credentials","Managing supply chain","Scheduling operating rooms"], correctIndex: 0, rationale: "EMPI links patient records across disparate systems. Duplicate and overlay management prevents patient safety risks and billing errors from misidentified patients.", difficulty: 2, category: "Health Informatics", topic: "Patient Identity Management" },
  { id: "him-999", stem: "A hybrid health record system:", options: ["Contains both paper and electronic components that together constitute the legal health record","Uses only paper records","Uses only electronic records","Has no legal standing"], correctIndex: 0, rationale: "Hybrid records combine paper and electronic elements. Organizations must define which components constitute the legal health record and the designated record set.", difficulty: 2, category: "Data Content & Structure", topic: "Record Systems" },
  { id: "him-1000", stem: "The Health Information Exchange (HIE) enables:", options: ["Electronic sharing of health information across different healthcare organizations to improve care coordination","Only internal data sharing","Paper record transfers","Patient scheduling across sites"], correctIndex: 0, rationale: "HIE facilitates electronic sharing of clinical data across organizations. Models include directed exchange, query-based, and consumer-mediated exchange.", difficulty: 2, category: "Health Informatics", topic: "Health Information Exchange" },
  { id: "him-1001", stem: "Under HIPAA, which is NOT considered a permitted use or disclosure without authorization?", options: ["Marketing communications using PHI","Treatment activities","Payment activities","Healthcare operations"], correctIndex: 0, rationale: "Marketing using PHI generally requires individual authorization. Treatment, payment, and healthcare operations (TPO) are permitted without authorization under HIPAA.", difficulty: 2, category: "Privacy & Confidentiality", topic: "HIPAA Uses & Disclosures" },
  { id: "him-1002", stem: "The Ambulatory Payment Classification (APC) system is used for:", options: ["Medicare outpatient hospital reimbursement under the Outpatient Prospective Payment System (OPPS)","Inpatient reimbursement","Physician office payments","Home health payments"], correctIndex: 0, rationale: "APCs classify outpatient services into groups for payment under OPPS. Each APC has a relative weight that determines the payment amount.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Systems" },
  { id: "him-1003", stem: "When coding sepsis, the ICD-10-CM guideline requires:", options: ["A code for the underlying systemic infection first, then R65.20 or R65.21 for severe sepsis if applicable","Only the sepsis code","Only the organism code","Coding sepsis only when documented as 'septic shock'"], correctIndex: 0, rationale: "Sepsis coding requires the underlying infection code (e.g., A41.9) sequenced first. R65.20 (severe sepsis without shock) or R65.21 (with shock) is added when severe sepsis is documented.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Sepsis Coding" },
  { id: "him-1004", stem: "A physician query is inappropriate when it:", options: ["Leads the provider to a specific diagnosis to increase reimbursement rather than clarify documentation","Asks about clinical significance of lab findings","Requests clarification of conflicting documentation","Provides clinical indicators for review"], correctIndex: 0, rationale: "Leading queries that suggest specific diagnoses for financial gain are inappropriate and may constitute fraud. Compliant queries present clinical facts and ask open-ended questions.", difficulty: 2, category: "Clinical Documentation", topic: "CDI Compliance" },
  { id: "him-1005", stem: "The LOINC (Logical Observation Identifiers Names and Codes) system is used primarily for:", options: ["Standardized identification of laboratory tests and clinical observations","Procedure coding for billing","Drug identification","Disease classification"], correctIndex: 0, rationale: "LOINC provides universal codes for laboratory and clinical observations, enabling interoperability of lab results across different systems and institutions.", difficulty: 2, category: "Health Informatics", topic: "Clinical Terminologies" },
  { id: "him-1006", stem: "Modifier -25 in CPT is appended to:", options: ["An E/M service to indicate a significant, separately identifiable evaluation performed on the same day as a procedure","All surgical procedures","Laboratory tests","Radiology services"], correctIndex: 0, rationale: "Modifier -25 indicates the E/M service was significant and separately identifiable from any procedure performed on the same day. Documentation must support the separate service.", difficulty: 3, category: "Clinical Classification", topic: "CPT Modifiers" },
  { id: "him-1007", stem: "Revenue code 0450 on a UB-04 claim form represents:", options: ["Emergency room services","Operating room services","Pharmacy services","Laboratory services"], correctIndex: 0, rationale: "Revenue code 0450 is the general emergency room charge code. Revenue codes classify institutional charges by department/service type on the UB-04.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Codes" },
  { id: "him-1008", stem: "A business associate agreement (BAA) under HIPAA must:", options: ["Establish permitted uses/disclosures of PHI, require safeguards, and mandate breach reporting","Only identify the business associate by name","Be renewed annually","Be filed with HHS"], correctIndex: 0, rationale: "BAAs must define permitted PHI uses, require appropriate safeguards, mandate breach reporting, ensure subcontractor compliance, and return/destroy PHI upon termination.", difficulty: 2, category: "Privacy & Confidentiality", topic: "Business Associates" },
  { id: "him-1009", stem: "In ICD-10-CM, an Excludes1 note means:", options: ["The two conditions cannot occur together — the excluded code should never be used with the code above the note","The conditions can occur together but are coded separately","The excluded code replaces the listed code","No relationship exists between the codes"], correctIndex: 0, rationale: "Excludes1 = mutually exclusive — conditions cannot coexist. Excludes2 = not included here but can coexist — code both if documented.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Conventions" },
  { id: "him-1010", stem: "Clinical quality measures (CQMs) are used to:", options: ["Quantify healthcare processes, outcomes, and patient experiences for quality improvement and value-based reporting","Set staff salaries","Determine bed capacity","Schedule physician vacations"], correctIndex: 0, rationale: "CQMs track evidence-based measures (process, outcome, structure, patient experience) for quality reporting programs like MIPS and hospital value-based purchasing.", difficulty: 2, category: "Health Informatics", topic: "Quality Measurement" },
  { id: "him-1011", stem: "The Medicare Severity DRG (MS-DRG) system has how many severity tiers for most base DRGs?", options: ["Three: without CC/MCC, with CC, and with MCC","Two: with or without complications","Four tiers","One tier"], correctIndex: 0, rationale: "Most MS-DRG base groups have three tiers: without CC/MCC (lowest weight), with CC (middle), and with MCC (highest weight), reflecting increasing resource use.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Systems" },
  { id: "him-1012", stem: "De-identified health information under HIPAA:", options: ["Has had 18 specific identifiers removed (Safe Harbor method) or meets expert determination standard","Is always automatically de-identified in the EHR","Cannot be used for any purpose","Requires patient consent for any use"], correctIndex: 0, rationale: "HIPAA de-identification: Safe Harbor removes 18 identifiers, or Expert Determination uses statistical methods to verify very small re-identification risk.", difficulty: 3, category: "Privacy & Confidentiality", topic: "De-identification" },
  { id: "him-1013", stem: "Telehealth coding requires which place of service (POS) code when the patient is at home?", options: ["POS 10 (Telehealth Provided in Patient's Home)","POS 11 (Office)","POS 02 (Telehealth — distant site)","POS 21 (Inpatient Hospital)"], correctIndex: 0, rationale: "POS 10 was introduced for telehealth services rendered to patients in their homes. POS 02 is used when the patient is at a telehealth-capable distant site facility.", difficulty: 3, category: "Clinical Classification", topic: "Telehealth Coding" },
  { id: "him-1014", stem: "The Physician Quality Reporting System (PQRS) has been replaced by:", options: ["Merit-based Incentive Payment System (MIPS) under MACRA","Hospital Value-Based Purchasing","Meaningful Use Stage 3","The Recovery Audit Program"], correctIndex: 0, rationale: "MACRA consolidated PQRS, Meaningful Use, and the Value Modifier into MIPS. MIPS measures quality, promoting interoperability, improvement activities, and cost.", difficulty: 2, category: "Revenue Cycle Management", topic: "Value-Based Payment" },
  { id: "him-1015", stem: "A legal health record (LHR) is defined as:", options: ["The subset of patient health information generated or maintained by a healthcare organization that constitutes the business record for legal purposes","Every piece of data in the EHR","Only paper documents","Only billing records"], correctIndex: 0, rationale: "The LHR is the organization-defined subset of health information used to support legal, business, and disclosure requirements. It may differ from the designated record set.", difficulty: 2, category: "Data Content & Structure", topic: "Legal Health Record" },
  { id: "him-1016", stem: "Natural language processing (NLP) in HIM can:", options: ["Extract structured data from unstructured clinical narratives for coding, quality reporting, and analytics","Only process billing data","Replace all manual coding immediately","Work only with handwritten notes"], correctIndex: 0, rationale: "NLP analyzes free-text clinical documentation to extract diagnoses, procedures, and clinical facts. Used in CAC, CDI, quality measure extraction, and research.", difficulty: 2, category: "Health Informatics", topic: "NLP Technology" },
  { id: "him-1017", stem: "A root cause analysis (RCA) in healthcare quality improvement:", options: ["Investigates adverse events to identify underlying system failures and prevent recurrence","Assigns blame to individuals","Is required only for billing errors","Focuses only on equipment failures"], correctIndex: 0, rationale: "RCA is a structured methodology examining contributing factors to adverse events. It focuses on system and process failures rather than individual blame, leading to corrective actions.", difficulty: 2, category: "Health Informatics", topic: "Quality Improvement" },
  { id: "him-1018", stem: "The ICD-10-PCS root operation 'Replacement' differs from 'Supplement' in that:", options: ["Replacement removes the body part and puts in a biological or synthetic substitute; Supplement reinforces without removing","Both involve removing tissue","Supplement always uses synthetic material","Replacement only applies to joints"], correctIndex: 0, rationale: "Replacement (R): eradicate and substitute. Supplement (U): reinforce/augment without removing. Example: total hip replacement vs. mesh reinforcement of a hernia.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-PCS Root Operations" },
  { id: "him-1019", stem: "Patient portal functionality under Promoting Interoperability includes:", options: ["Patient electronic access to health information, secure messaging, and ability to request amendments","Only appointment scheduling","Physical access to paper records","Telephone-only communication"], correctIndex: 0, rationale: "Promoting Interoperability measures require patient portal access to view/download/transmit records, secure messaging, and patient-generated health data capabilities.", difficulty: 2, category: "Health Informatics", topic: "Patient Engagement" },
  { id: "him-1020", stem: "The False Claims Act (FCA) in healthcare:", options: ["Imposes liability for knowingly submitting false claims to federal healthcare programs with treble damages and per-claim penalties","Only applies to pharmaceutical companies","Has no whistleblower provisions","Requires proof of specific intent to defraud"], correctIndex: 0, rationale: "The FCA covers knowingly false/fraudulent claims to the government. Includes qui tam (whistleblower) provisions. 'Knowing' includes deliberate ignorance and reckless disregard.", difficulty: 3, category: "Legal & Compliance", topic: "Fraud & Abuse Laws" },
  { id: "him-1021", stem: "Abstracting in HIM refers to:", options: ["Extracting specific data elements from a health record for databases, registries, and reporting purposes","Writing a summary of a research article","Removing patient identifiers","Destroying old records"], correctIndex: 0, rationale: "Abstracting is the process of extracting defined data elements from health records for cancer registries, quality databases, birth certificates, and other reporting needs.", difficulty: 1, category: "Data Content & Structure", topic: "Data Abstraction" },
  { id: "him-1022", stem: "In CPT, modifier -59 indicates:", options: ["A distinct procedural service that is separate and independent from other services performed on the same day","A bilateral procedure","A repeat procedure by the same physician","An unplanned return to the OR"], correctIndex: 0, rationale: "Modifier -59 indicates a distinct procedural service: different session, different procedure/surgery, different site/organ system, or separate incision/excision. Used to bypass NCCI edits.", difficulty: 3, category: "Clinical Classification", topic: "CPT Modifiers" },
  { id: "him-1023", stem: "The retention period for medical records is determined by:", options: ["State law, federal regulations, and organizational policy — whichever is longest","The physician's preference","Only federal law","A standard 5-year period for all states"], correctIndex: 0, rationale: "Retention requirements vary by state and record type. Organizations must comply with the longest applicable requirement (state, federal, accreditation, statute of limitations).", difficulty: 2, category: "Legal & Compliance", topic: "Record Retention" },
  { id: "him-1024", stem: "Unbundling in medical coding refers to:", options: ["Separately billing components of a procedure that should be reported as a single comprehensive code","Combining multiple procedures into one code","Using modifiers appropriately","Sequencing codes correctly"], correctIndex: 0, rationale: "Unbundling is a fraudulent practice of breaking down a bundled procedure into component parts to increase reimbursement. NCCI edits help detect unbundling.", difficulty: 2, category: "Legal & Compliance", topic: "Coding Compliance" },
  { id: "him-1025", stem: "A contingency plan under HIPAA Security Rule must include:", options: ["Data backup plan, disaster recovery plan, and emergency mode operation plan","Only antivirus software","Physical security measures only","Employee handbook"], correctIndex: 0, rationale: "HIPAA Security Rule requires contingency planning with data backup, disaster recovery, emergency operations, testing/revision procedures, and criticality analysis.", difficulty: 3, category: "Privacy & Confidentiality", topic: "HIPAA Security Rule" },
  { id: "him-1026", stem: "ICD-10-CM guidelines for pressure ulcers require coding:", options: ["The site, laterality, and stage of each pressure ulcer separately","Only the most severe pressure ulcer","A single code for all pressure ulcers","Only pressure ulcers present on admission"], correctIndex: 0, rationale: "Each pressure ulcer is coded separately by site, laterality, and stage. Unstageable and deep tissue injury have separate codes. Document both current and healed stages.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-CM Injury Coding" },
  { id: "him-1027", stem: "The Stark Law (Physician Self-Referral Law) prohibits:", options: ["Physicians from referring Medicare/Medicaid patients to entities with which they have a financial relationship, unless an exception applies","All physician referrals","Only kickback payments","Only referrals to out-of-state facilities"], correctIndex: 0, rationale: "Stark Law is a strict liability statute prohibiting self-referrals for designated health services to entities with financial relationships, subject to defined exceptions.", difficulty: 3, category: "Legal & Compliance", topic: "Fraud & Abuse Laws" },
  { id: "him-1028", stem: "Predictive analytics in healthcare can be used for:", options: ["Identifying patients at high risk for readmission, predicting disease progression, and optimizing resource allocation","Only financial forecasting","Replacing clinical decision-making","Scheduling maintenance"], correctIndex: 0, rationale: "Predictive analytics uses statistical models and machine learning on historical data to predict outcomes: readmission risk, sepsis onset, disease progression, resource needs.", difficulty: 2, category: "Health Informatics", topic: "Healthcare Analytics" },
  { id: "him-1029", stem: "The designated record set (DRS) under HIPAA includes:", options: ["Medical records, billing records, enrollment/payment records, and other records used to make decisions about individuals","Only billing records","Only electronic records","Only records less than 5 years old"], correctIndex: 0, rationale: "DRS includes any records used to make decisions about individuals: medical records, billing records, health plan enrollment/payment records, and case management records.", difficulty: 2, category: "Privacy & Confidentiality", topic: "HIPAA Record Access" },
  { id: "him-1030", stem: "Grouper software in DRG assignment:", options: ["Takes coded data (diagnoses, procedures, demographics) and assigns the appropriate DRG based on CMS logic","Physically groups patient charts","Creates physician schedules","Manages bed assignments"], correctIndex: 0, rationale: "Grouper software processes principal diagnosis, secondary diagnoses, procedures, age, sex, and discharge status to assign the most appropriate DRG per CMS algorithms.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-1031", stem: "The minimum necessary standard under HIPAA requires:", options: ["Limiting PHI use, disclosure, and requests to the minimum amount needed to accomplish the intended purpose","Sharing all available PHI for any request","No restrictions on internal use","Full records for every insurance request"], correctIndex: 0, rationale: "Minimum necessary limits PHI to what is reasonably necessary for the purpose. Exceptions include treatment purposes, patient requests, and legally required disclosures.", difficulty: 2, category: "Privacy & Confidentiality", topic: "HIPAA Minimum Necessary" },
  { id: "him-1032", stem: "A clinical data warehouse differs from an operational database in that:", options: ["It integrates data from multiple sources for analytics and reporting rather than daily transaction processing","It only stores billing data","It replaces the EHR","It is updated in real-time for clinical care"], correctIndex: 0, rationale: "Clinical data warehouses aggregate data from multiple sources (EHR, billing, lab, pharmacy) for analytics, research, and reporting. They are optimized for queries, not transactions.", difficulty: 3, category: "Health Informatics", topic: "Data Warehousing" },
  { id: "him-1033", stem: "The ICD-10-CM seventh character 'A' for injury codes indicates:", options: ["Initial encounter — active phase of treatment","Subsequent encounter","Sequela","Healed fracture"], correctIndex: 0, rationale: "7th character A = initial encounter (active treatment phase, not just first visit). D = subsequent encounter (routine care during healing). S = sequela (late effect).", difficulty: 2, category: "Clinical Classification", topic: "ICD-10-CM Injury Coding" },
  { id: "him-1034", stem: "Revenue integrity in healthcare ensures:", options: ["Accurate charge capture, compliant billing practices, and appropriate reimbursement for services rendered","Maximum possible billing regardless of services","Denial of all underpayment appeals","Only outpatient charge accuracy"], correctIndex: 0, rationale: "Revenue integrity encompasses accurate CDM maintenance, charge capture validation, compliant coding/billing, denial management, and ensuring appropriate reimbursement.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Integrity" },
  { id: "him-1035", stem: "Blockchain technology in healthcare could:", options: ["Provide immutable, decentralized records for secure health information exchange and patient identity verification","Replace all EHR systems immediately","Only be used for cryptocurrency payments","Violate HIPAA by nature"], correctIndex: 0, rationale: "Blockchain offers potential for secure, tamper-proof health data exchange, patient identity management, consent tracking, and supply chain integrity in healthcare.", difficulty: 3, category: "Health Informatics", topic: "Emerging Technologies" },
  { id: "him-1036", stem: "A clean claim in the revenue cycle is:", options: ["A claim that passes all edits and can be processed without additional information from the provider","A claim that has been denied and resubmitted","Any claim submitted within 30 days","A claim with no charges"], correctIndex: 0, rationale: "Clean claims meet all payer requirements for processing: correct patient/provider info, valid codes, proper modifiers, required authorizations, and complete documentation.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Management" },
  { id: "him-1037", stem: "The AHIMA Standards of Ethical Coding include:", options: ["Coding only what is documented, refusing to code for financial gain, and reporting compliance concerns","Coding to maximize reimbursement","Following physician orders to upcode","Ignoring documentation deficiencies"], correctIndex: 0, rationale: "AHIMA ethical coding standards: code only documented conditions, refuse upcoding/unbundling, report compliance concerns, maintain competency, and protect data integrity.", difficulty: 1, category: "Legal & Compliance", topic: "Ethical Coding" },
  { id: "him-1038", stem: "Clinical documentation for procedures must include:", options: ["Indication, description of the procedure, findings, complications, and specimens removed","Only the procedure name","Only the billing code","Only the operating physician's name"], correctIndex: 0, rationale: "Complete procedural documentation includes indications, consent, technique, findings, complications, specimens, estimated blood loss, and post-procedure condition.", difficulty: 2, category: "Data Content & Structure", topic: "Documentation Requirements" },
  { id: "him-1039", stem: "The ICD-10-PCS qualifier character provides:", options: ["Additional specificity about the procedure such as diagnostic vs. therapeutic, device type, or qualitative information","The body part operated on","The surgical approach","The section of the classification"], correctIndex: 0, rationale: "The 7th character (qualifier) adds specificity: diagnostic/therapeutic distinction, specific anatomic detail, direction, or other qualifying information unique to the root operation.", difficulty: 3, category: "Clinical Classification", topic: "ICD-10-PCS Structure" },
  { id: "him-1040", stem: "Population health management uses HIM data for:", options: ["Identifying health trends, risk stratification, care gap analysis, and targeted interventions across defined populations","Individual patient treatment only","Facility construction planning","Staff recruitment"], correctIndex: 0, rationale: "Population health leverages aggregate health data for risk stratification, chronic disease management, preventive care targeting, and health outcome improvement.", difficulty: 2, category: "Health Informatics", topic: "Population Health" },
  { id: "him-1041", stem: "A 72-hour rule for outpatient services means:", options: ["Outpatient diagnostic services provided within 72 hours before an inpatient admission are bundled into the inpatient claim","All outpatient visits must be within 72 hours","Discharge must occur within 72 hours","Claims must be filed within 72 hours"], correctIndex: 0, rationale: "The 72-hour (3-day) payment window bundles outpatient diagnostic services (and related non-diagnostic services) provided in the 3 days before an inpatient admission into the DRG payment.", difficulty: 3, category: "Revenue Cycle Management", topic: "Payment Rules" },
  { id: "him-1042", stem: "Health information governance (HIG) encompasses:", options: ["Strategic management of health information across the enterprise including quality, integrity, protection, and availability","Only IT security measures","Paper record filing systems","Patient scheduling systems"], correctIndex: 0, rationale: "HIG is a comprehensive framework covering data governance, information governance, IT governance, and clinical governance to ensure trustworthy health information.", difficulty: 2, category: "Health Informatics", topic: "Information Governance" },
  { id: "him-1043", stem: "The CMS-1500 claim form is used for:", options: ["Professional/physician services billed to Medicare and other payers","Institutional/facility claims","Dental claims","Workers' compensation claims exclusively"], correctIndex: 0, rationale: "CMS-1500 (HCFA-1500) is the standard claim form for professional services. The UB-04 (CMS-1450) is used for institutional/facility claims.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claim Forms" },
  { id: "him-1044", stem: "Longitudinal health records:", options: ["Follow a patient across time and multiple care settings, providing a comprehensive health history","Cover only a single encounter","Are limited to inpatient stays","Cannot be maintained electronically"], correctIndex: 0, rationale: "Longitudinal records span the patient's lifetime across providers and settings. HIEs and patient portals support longitudinal record access for better care coordination.", difficulty: 2, category: "Data Content & Structure", topic: "Record Types" },
  { id: "him-1045", stem: "Workflow analysis in HIM:", options: ["Examines processes to identify inefficiencies, bottlenecks, and opportunities for improvement in health information management","Only measures employee productivity","Is limited to coding workflows","Cannot use technology tools"], correctIndex: 0, rationale: "Workflow analysis maps current processes, identifies inefficiencies, and designs improved workflows. Tools include flowcharts, process maps, and time-motion studies.", difficulty: 2, category: "Health Informatics", topic: "Process Improvement" },
  { id: "him-1046", stem: "Under HIPAA, a breach notification to affected individuals must occur within:", options: ["60 days of discovering the breach","24 hours","7 days","1 year"], correctIndex: 0, rationale: "HIPAA Breach Notification Rule requires individual notification without unreasonable delay, no later than 60 days from discovery. HHS notification timing depends on breach size.", difficulty: 2, category: "Privacy & Confidentiality", topic: "Breach Notification" },
  { id: "him-1047", stem: "ICD-10-CM laterality coding requires:", options: ["Specifying right, left, or bilateral when the classification provides laterality options","Always coding bilateral","Laterality for all codes","Ignoring laterality for extremity codes"], correctIndex: 0, rationale: "ICD-10-CM includes laterality for many codes. Coders must specify right/left/bilateral based on documentation. An unspecified laterality code should only be used when documentation is unclear.", difficulty: 2, category: "Clinical Classification", topic: "ICD-10-CM Specificity" },
  { id: "him-1048", stem: "A clinical data repository (CDR) is:", options: ["A real-time database that collects and stores clinical data from multiple systems for point-of-care access","A physical file room","An archival storage facility","A billing-only database"], correctIndex: 0, rationale: "CDR aggregates clinical data from various sources (lab, pharmacy, radiology, ADT) in real-time for clinician access at the point of care, supporting clinical decision-making.", difficulty: 2, category: "Health Informatics", topic: "Health IT Infrastructure" },
  { id: "him-1049", stem: "Coding audit methodologies include:", options: ["Prospective, concurrent, and retrospective reviews of coded data for accuracy and compliance","Only retrospective reviews after billing","Only external audits by RACs","Only physician-led reviews"], correctIndex: 0, rationale: "Coding audits can be prospective (pre-billing), concurrent (during stay), or retrospective (post-billing). Internal and external audits assess accuracy, compliance, and documentation quality.", difficulty: 2, category: "Legal & Compliance", topic: "Coding Audits" },
  { id: "him-1050", stem: "The HIPAA Security Rule requires covered entities to:", options: ["Implement administrative, physical, and technical safeguards to protect electronic PHI","Only protect paper records","Encrypt all data at all times without exception","Share all security protocols publicly"], correctIndex: 0, rationale: "The Security Rule mandates three safeguard categories: administrative (policies, training), physical (facility access, workstation security), and technical (access controls, encryption, audit controls).", difficulty: 2, category: "Privacy & Confidentiality", topic: "HIPAA Security Rule" },
  { id: "him-1051", stem: "ICD-10-CM combination codes:", options: ["Represent two or more conditions or a condition with a complication in a single code, eliminating the need for multiple codes","Always require additional codes","Cannot capture complications","Are limited to injury codes only"], correctIndex: 0, rationale: "Combination codes capture multiple elements: disease with manifestation (E11.311 Type 2 DM with retinopathy), etiology with manifestation, or poisoning with intent and substance.", difficulty: 2, category: "Clinical Classification", topic: "ICD-10-CM Conventions" },
  { id: "him-1052", stem: "Telehealth modifier -95 is used to indicate:", options: ["A synchronous telemedicine service using real-time interactive audio and video communication","An asynchronous store-and-forward service","An in-person service","A telephone-only service"], correctIndex: 0, rationale: "Modifier -95 indicates synchronous (real-time) telemedicine via interactive audio-video. Modifier -FQ is used for services furnished via audio-only technology.", difficulty: 3, category: "Clinical Classification", topic: "Telehealth Coding" },
];
